#!/usr/bin/env node
// 飞书云文档表格备份脚本 - 将workspace关键文件元数据备份到云文档表格
// 使用UTF-8编码，自动去重
// V2: 增加HTTP状态码检查，更健壮的错误处理

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');
const https = require('https');

// 配置
const APP_ID = process.env.FEISHU_APP_ID || 'cli_a93fd942c2f85cd6';
const APP_SECRET = process.env.FEISHU_APP_SECRET || '5D5d8tixIMAZH5zaWpn3SgVUlG8p0aT6';
const DOC_TITLE = 'OpenClaw 备份索引';
const WORKSPACE_ROOT = path.join(process.env.USERPROFILE, '.openclaw', 'workspace');

// 表格字段设计（8列）
const TABLE_COLUMNS = [
    { name: '文件名', width: 200 },
    { name: '文件类型', width: 150 },
    { name: '本地路径', width: 300 },
    { name: '备份时间', width: 180 },
    { name: '文件大小', width: 80 },
    { name: '文件哈希', width: 150 },
    { name: '状态', width: 100 },
    { name: '备注', width: 200 }
];

// 计算SHA256哈希
function computeHash(filePath) {
    const hash = crypto.createHash('sha256');
    const data = fs.readFileSync(filePath);
    hash.update(data);
    return hash.digest('hex');
}

// 获取租户访问令牌
async function getTenantAccessToken() {
    return new Promise((resolve, reject) => {
        const body = JSON.stringify({ app_id: APP_ID, app_secret: APP_SECRET });
        const options = {
            hostname: 'open.feishu.cn',
            port: 443,
            path: '/open-apis/auth/v3/tenant_access_token/internal',
            method: 'POST',
            headers: {
                'Content-Type': 'application/json; charset=utf-8',
                'Content-Length': Buffer.byteLength(body, 'utf8')
            }
        };

        const req = https.request(options, (res) => {
            let data = '';
            res.on('data', chunk => data += chunk);
            res.on('end', () => {
                if (res.statusCode !== 200) {
                    reject(new Error(`Auth HTTP ${res.statusCode}: ${data.substring(0, 200)}`));
                    return;
                }
                try {
                    const result = JSON.parse(data);
                    if (result.code === 0 && result.tenant_access_token) {
                        resolve(result.tenant_access_token);
                    } else {
                        reject(new Error(`Get token failed: ${result.msg || data}`));
                    }
                } catch (e) {
                    reject(new Error(`Auth parse error: ${data.substring(0, 200)}`));
                }
            });
        });

        req.on('error', reject);
        req.write(body);
        req.end();
    });
}

// 列出所有文档（分页）
async function listDocuments(token, pageSize = 50) {
    return new Promise((resolve, reject) => {
        const options = {
            hostname: 'open.feishu.cn',
            port: 443,
            path: `/open-apis/docx/v1/documents?page_size=${pageSize}`,
            method: 'GET',
            headers: {
                'Authorization': `Bearer ${token}`
            }
        };

        const req = https.request(options, (res) => {
            let data = '';
            res.on('data', chunk => data += chunk);
            res.on('end', () => {
                if (res.statusCode !== 200) {
                    reject(new Error(`List HTTP ${res.statusCode}: ${data.substring(0, 200)}`));
                    return;
                }
                try {
                    const result = JSON.parse(data);
                    if (result.code === 0 && result.data && result.data.documents) {
                        resolve(result.data.documents);
                    } else {
                        reject(new Error(`List documents failed: ${result.msg || JSON.stringify(result)}`));
                    }
                } catch (e) {
                    reject(new Error(`List parse error: ${e.message}, raw: ${data.substring(0, 200)}`));
                }
            });
        });

        req.on('error', reject);
        req.end();
    });
}

// 查找文档（通过列出后匹配标题）
async function findDoc(token, title) {
    try {
        const docs = await listDocuments(token, 100);
        const match = docs.find(d => d.title === title);
        return match || null;
    } catch (e) {
        throw e;
    }
}

// 创建文档
async function createDoc(token, title) {
    return new Promise((resolve, reject) => {
        const body = JSON.stringify({ title: title });
        const options = {
            hostname: 'open.feishu.cn',
            port: 443,
            path: '/open-apis/docx/v1/documents',
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${token}`,
                'Content-Type': 'application/json; charset=utf-8',
                'Content-Length': Buffer.byteLength(body, 'utf8')
            }
        };

        const req = https.request(options, (res) => {
            let data = '';
            res.on('data', chunk => data += chunk);
            res.on('end', () => {
                if (res.statusCode !== 200) {
                    reject(new Error(`Create doc HTTP ${res.statusCode}: ${data.substring(0, 200)}`));
                    return;
                }
                try {
                    console.log(`[DEBUG] createDoc status: ${res.statusCode}, body: ${data.substring(0, 500)}`);
                    const result = JSON.parse(data);
                    if (result.data && result.data.document_id) {
                        resolve(result.data);
                    } else {
                        reject(new Error(`Create doc failed: ${result.msg || data}`));
                    }
                } catch (e) {
                    reject(new Error(`Create parse error: ${data.substring(0, 200)}`));
                }
            });
        });

        req.on('error', reject);
        req.write(body);
        req.end();
    });
}

