// 创建表格
async function createTable(token, docId) {
    return new Promise((resolve, reject) => {
        const body = JSON.stringify({
            block_type: 'table',
            table: {
                row_size: 1,
                column_size: TABLE_COLUMNS.length
            }
        });

        const options = {
            hostname: 'open.feishu.cn',
            port: 443,
            path: `/open-apis/docx/v1/documents/${docId}/blocks`,
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${token}`,
                'Content-Type': 'application/json; charset=utf-8',
                'Content-Length': Buffer.byteLength(body, 'utf8')
            }
        };

        const req = https.request(options, (res) => {
            let data = '';
            res.on('data', chunk => data += chunk);
            res.on('end', () => {
                if (res.statusCode !== 200) {
                    reject(new Error(`Create table HTTP ${res.statusCode}: ${data.substring(0, 200)}`));
                    return;
                }
                try {
                    const result = JSON.parse(data);
                    if (result.data && result.data.block) {
                        resolve(result.data.block);
                    } else {
                        reject(new Error(`Create table failed: ${result.msg || data}`));
                    }
                } catch (e) {
                    reject(e);
                }
            });
        });

        req.on('error', reject);
        req.write(body);
        req.end();
    });
}

// 批量写入表格单元格
async function writeTableCells(token, docId, tableBlockId, values) {
    return new Promise((resolve, reject) => {
        const children = [];
        for (let r = 0; r < values.length; r++) {
            for (let c = 0; c < TABLE_COLUMNS.length; c++) {
                children.push({
                    block_type: 'text',
                    text: {
                        content: values[r][c] || ''
                    }
                });
            }
        }

        const body = JSON.stringify({ children: children });

        const options = {
            hostname: 'open.feishu.cn',
            port: 443,
            path: `/open-apis/docx/v1/documents/${docId}/blocks/${tableBlockId}/children/batch_create`,
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${token}`,
                'Content-Type': 'application/json; charset=utf-8',
                'Content-Length': Buffer.byteLength(body, 'utf8')
            }
        };

        const req = https.request(options, (res) => {
            let data = '';
            res.on('data', chunk => data += chunk);
            res.on('end', () => {
                if (res.statusCode !== 200) {
                    reject(new Error(`Write cells HTTP ${res.statusCode}: ${data.substring(0, 200)}`));
                    return;
                }
                try {
                    const result = JSON.parse(data);
                    if (result.code === 0) {
                        resolve(result.data);
                    } else {
                        reject(new Error(`Write cells failed: ${result.msg || data}`));
                    }
                } catch (e) {
                    reject(e);
                }
            });
        });

        req.on('error', reject);
        req.write(body);
        req.end();
    });
}

// 读取表格现有数据
async function readTableData(token, docId, tableBlockId) {
    return new Promise((resolve, reject) => {
        const options = {
            hostname: 'open.feishu.cn',
            port: 443,
            path: `/open-apis/docx/v1/documents/${docId}/blocks/${tableBlockId}/children`,
            method: 'GET',
            headers: {
                'Authorization': `Bearer ${token}`
            }
        };

        const req = https.request(options, (res) => {
            let data = '';
            res.on('data', chunk => data += chunk);
            res.on('end', () => {
                if (res.statusCode !== 200) {
                    reject(new Error(`Read table HTTP ${res.statusCode}: ${data.substring(0, 200)}`));
                    return;
                }
                try {
                    const result = JSON.parse(data);
                    if (result.code === 0 && result.data && result.data.children) {
                        const children = result.data.children;
                        const rows = [];
                        for (let i = 0; i < children.length; i += TABLE_COLUMNS.length) {
                            const row = [];
                            for (let j = 0; j < TABLE_COLUMNS.length; j++) {
                                const cell = children[i + j];
                                row.push(cell && cell.text ? cell.text.content : '');
                            }
                            rows.push(row);
                        }
                        resolve(rows);
                    } else {
                        resolve([]);
                    }
                } catch (e) {
                    reject(e);
                }
            });
        });

        req.on('error', reject);
        req.end();
    });
}

// 扫描workspace文件
function scanWorkspaceFiles(rootDir) {
    const files = [];
    const excludeDirs = new Set(['node_modules', '.git', '.openclaw', 'scripts', 'self-improving', 'conversation-backup']);

    function walk(dir, relative = '') {
        try {
            const entries = fs.readdirSync(dir, { withFileTypes: true });
            for (const entry of entries) {
                if (excludeDirs.has(entry.name)) continue;

                const fullPath = path.join(dir, entry.name);
                const relPath = path.join(relative, entry.name);

                if (entry.isDirectory()) {
                    walk(fullPath, relPath);
                } else {
                    try {
                        const stats = fs.statSync(fullPath);
                        const ext = path.extname(entry.name).toLowerCase();
                        let fileType = '其他';
                        if (ext === '.js' || ext === '.ts' || ext === '.py' || ext === '.ps1' || ext === '.sh') fileType = '脚本';
                        else if (ext === '.md') fileType = '文档';
                        else if (ext === '.json') fileType = '配置';
                        else if (ext === '.log') fileType = '日志';
                        else if (ext === '.txt') fileType = '文本';

                        files.push({
                            name: entry.name,
                            type: fileType,
                            path: relPath,
                            size: stats.size,
                            hash: computeHash(fullPath),
                            mtime: stats.mtime.toISOString()
                        });
                    } catch (e) {
                        // 忽略错误
                    }
                }
            }
        } catch (e) {
            // 目录不可访问则跳过
        }
    }

    walk(rootDir);
    return files;
}

// 主函数
async function backupToDocTable() {
    console.log('开始备份workspace文件元数据到云文档表格...');
    const sessionTime = new Date().toISOString();

    try {
        // 1. 获取访问令牌
        console.log('获取飞书访问令牌...');
        const token = await getTenantAccessToken();
        console.log('✅ 令牌获取成功');

        // 2. 查找或创建文档
        let doc = await findDoc(token, DOC_TITLE);
        if (!doc) {
            console.log(`未找到文档 "${DOC_TITLE}"，创建新文档...`);
            doc = await createDoc(token, DOC_TITLE);
        }
        const docId = doc.document_id;
        console.log(`使用文档: ${docId} (${doc.title})`);

        // 3. 查找现有表格
        console.log('查找文档中的表格...');
        const blocks = await getDocumentBlocks(token, docId);
        let tableBlock = blocks.find(b => b.block_type === 'table');

        if (!tableBlock) {
            console.log('未找到表格，创建新表格...');
            tableBlock = await createTable(token, docId);
            // 写入表头
            const headers = TABLE_COLUMNS.map(col => col.name);
            await writeTableCells(token, docId, tableBlock.block_id, [headers]);
            console.log('✅ 表头已写入');
        } else {
            console.log(`✅ 找到现有表格: ${tableBlock.block_id}`);
        }

        // 4. 读取现有表格数据用于去重
        console.log('读取现有备份记录以去重...');
        const existingData = await readTableData(token, docId, tableBlock.block_id);
        const existingKeys = new Set();
        for (let i = 1; i < existingData.length; i++) {
            const row = existingData[i];
            if (row.length >= 6) {
                existingKeys.add(`${row[0]}|${row[5]}`);
            }
        }
        console.log(`现有记录数: ${existingKeys.size}`);

        // 5. 扫描文件
        console.log('扫描workspace文件...');
        const files = scanWorkspaceFiles(WORKSPACE_ROOT);
        console.log(`发现 ${files.length} 个文件`);

        // 6. 准备新记录
        const newRecords = [];
        for (const file of files) {
            const key = `${file.name}|${file.hash}`;
            if (!existingKeys.has(key)) {
                newRecords.push([
                    file.name,
                    file.type,
                    file.path,
                    sessionTime,
                    file.size.toString(),
                    file.hash,
                    '成功',
                    ''
                ]);
            }
        }

        console.log(`新增 ${newRecords.length} 条备份记录`);

        // 7. 写入新记录
        if (newRecords.length > 0) {
            await writeTableCells(token, docId, tableBlock.block_id, newRecords);
            console.log(`✅ 写入完成，新增 ${newRecords.length} 行`);
        } else {
            console.log('✅ 无新增记录（所有文件均已备份）');
        }

        // 8. 输出实验数据（供父session解析）
        console.log(JSON.stringify({
            experiment: {
                session: process.env.OPENCLAW_SESSION_NUMBER || 'unknown',
                type: 'backup_to_doc_table',
                timestamp: sessionTime,
                docId: docId,
                tableBlockId: tableBlock.block_id,
                scannedFiles: files.length,
                newRecords: newRecords.length,
                status: 'SUCCESS'
            }
        }));

        console.log('\n🎉 备份完成！');

    } catch (error) {
        console.error(`❌ 备份失败：${error.message}`);
        console.log(JSON.stringify({
            experiment: {
                session: process.env.OPENCLAW_SESSION_NUMBER || 'unknown',
                type: 'backup_to_doc_table',
                timestamp: sessionTime,
                status: 'FAILED',
                error: error.message
            }
        }));
        process.exit(1);
    }
}

backupToDocTable();

