// 主函数
async function backupToDocTable() {
    console.log('开始备份workspace文件元数据到云文档表格...');
    const sessionTime = new Date().toISOString();

    try {
        // 1. 获取访问令牌
        console.log('获取飞书访问令牌...');
        const token = await getTenantAccessToken();
        console.log('✅ 令牌获取成功');

        // 2. 直接使用已知文档和表格ID
        const docId = DOC_ID;
        const tableBlockId = TABLE_BLOCK_ID;
        console.log(`使用文档: ${docId} 表格: ${tableBlockId}`);

        // 3. 读取现有表格数据用于去重
        console.log('读取现有备份记录以去重...');
        const existingData = await readTableData(token, docId, tableBlockId);
        const existingKeys = new Set();
        for (let i = 1; i < existingData.length; i++) {
            const row = existingData[i];
            if (row.length >= 6) {
                existingKeys.add(`${row[0]}|${row[5]}`);
            }
        }
        console.log(`现有记录数: ${existingKeys.size}`);

