// 主函数
async function backupToDocTable() {
    console.log('开始备份workspace文件元数据到云文档表格...');
    const sessionTime = new Date().toISOString();

    try {
        // 1. 获取访问令牌
        console.log('获取飞书访问令牌...');
        const token = await getTenantAccessToken();
        console.log('✅ 令牌获取成功');

        // 2. 查找或创建文档
        let doc = await findDoc(token, DOC_TITLE);
        if (!doc) {
            console.log(`未找到文档 "${DOC_TITLE}"，创建新文档...`);
            doc = await createDoc(token, DOC_TITLE);
        }
        const docId = doc.document_id;
        console.log(`使用文档: ${docId} (${doc.title})`);

        // 3. 查找现有表格
        console.log('查找文档中的表格...');
        const blocks = await getDocumentBlocks(token, docId);
        let tableBlock = blocks.find(b => b.block_type === 'table');

        if (!tableBlock) {
            console.log('未找到表格，创建新表格...');
            tableBlock = await createTable(token, docId);
            // 写入表头
            const headers = TABLE_COLUMNS.map(col => col.name);
            await writeTableCells(token, docId, tableBlock.block_id, [headers]);
            console.log('✅ 表头已写入');
        } else {
            console.log(`✅ 找到现有表格: ${tableBlock.block_id}`);
        }

        // 4. 读取现有表格数据用于去重
        console.log('读取现有备份记录以去重...');
        const existingData = await readTableData(token, docId, tableBlock.block_id);
        const existingKeys = new Set();
        for (let i = 1; i < existingData.length; i++) {
            const row = existingData[i];
            if (row.length >= 6) {
                existingKeys.add(`${row[0]}|${row[5]}`);
            }
        }
